var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님. 괜찮으십니까?","JPN":"最高管理者様。大丈夫ですか？","ENG":"Administrator. Are you all right?","TWN":"管理者，你沒事吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 마침 위험하던 차에 잘 와줬네.","JPN":"ああ、まさに危ないところだった。よく来てくれた。","ENG":"Yes. You came just in the nick of time.","TWN":"不，你們來得正是時候。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어? 예니카 씨는 왜 갑자기 귀에 붕대를 감고 있는 거죠?","JPN":"あれ？　イェニカさんはどうして耳に包帯を巻いてるんですか？","ENG":"Oh? Why are Miss Yanikka's ears bandaged?","TWN":"嗯？耶妮卡的耳朵怎麼突然纏上繃帶……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 없는 사이에 내 목덜미를 노리더군.","JPN":"君たちがいない間に、私の首筋を狙って来たのでね。","ENG":"She went after my neck while you two were away.","TWN":"你們不在的時候，她想要咬我的脖子。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"귀의 근육을 튕겨서 튀어오를 줄은 미처 생각 못 했어.","JPN":"耳の筋肉を使って飛びかかるとは、予想もしていなかった。","ENG":"I had no idea she would use the muscles in her ear to bounce around.","TWN":"沒想到能靠著耳朵跳起來……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"처벌 사유가 하나 더 늘었군요.","JPN":"処罰する理由がまた1つ増えましたね。","ENG":"Another reason to punish her.","TWN":"又多了一條處罰的理由呢。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데, 함께 온 아가씨는 누구지?","JPN":"ところで、一緒に来たお嬢さんは誰かな？","ENG":"But, who's the lady you came with?","TWN":"不過，和你一起來的那位小姐是誰？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"북방합의체 장교 레노어. 처음으로 인사드려요.","JPN":"北方合意体の将校レノア。お初にお目にかかります。","ENG":"I am Officer Lenore of the Northern Union. Pleased to meet you.","TWN":"我是北方和議會軍官蕾諾雅。初次見面，請多關照。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"당신을 만나뵙고 싶었답니다, 최고관리자.","JPN":"あなたにお会いしたかったですわ、最高管理者。","ENG":"I've been wanting to meet you, Supreme Administrator.","TWN":"很早就想見你了，最高管理者。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우릴 잡으려고 온 듯한 분위기는 아니군 그래.","JPN":"私たちを捕まえるために来たような雰囲気ではないな。","ENG":"You don't seem to be here to take us away.","TWN":"看來你不是來抓我們的。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"그럴 작정이었다면, 저런 풋내기 군인 둘 대신 군대를 동원했겠죠.","JPN":"そのつもりだったら、あんな青臭い軍人2人の代わりに軍隊を動かしていたはずでしょう。","ENG":"If I were, then I would've come with an army instead of two rookie soldiers.","TWN":"如果真打算那樣做的話，我應該會出動軍隊了，而不是派那兩個菜鳥新兵。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"전 당신을 도우러 온 거예요.","JPN":"私はあなたを助けに来ました。","ENG":"I am here to help you.","TWN":"長話短說吧，我是來幫你的。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"돕는다고? 어떻게 말이지?","JPN":"助ける？　どうやって？","ENG":"Help me? How so?","TWN":"幫忙？你要怎麼幫？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"그라운드 제로를 습격했던 흰머리 카운터 꼬마. 당신의 부하죠?","JPN":"グラウンド・ゼロを襲撃した白髪のカウンターのチビ。あなたの部下ですわね？","ENG":"The silver-haired little Counter who attacked Ground Zero. She's your subordinate, is she not?","TWN":"襲擊G0的白髮制裁者小鬼，是你的部下吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_NOBG","text":{"KOREA":"그 꼬마. 지금 갇혀 있어요.","JPN":"あのチビ。今は閉じ込められています。","ENG":"That kid is trapped right now.","TWN":"那個孩子，現在被我們囚禁了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NOBG","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};